// Assemble bulletin: LLM stories + deterministic IOC appendix
// (IOCs always come from regex/feeds, never from the model).
const data = $('Normalize, Dedup & Extract IOCs').first().json;
let out = $json.message?.content ?? $json.output ?? {};
if (typeof out === 'string') {
  try { out = JSON.parse((out.match(/\{[\s\S]*\}/) || ['{}'])[0]); } catch (e) { out = {}; }
}
// Sanitize LLM prose for Slack/HTML, and only allow http(s) links that were
// actually present in the source items — the model must not mint URLs.
const clean = s => String(s ?? '').replace(/[<>@]/g, '').slice(0, 600);
const knownLinks = new Set(data.items.map(i => i.link).filter(Boolean));
const stories = (Array.isArray(out.stories) && out.stories.length
  ? out.stories.map(s => ({
      headline: clean(s.headline),
      sources: Array.isArray(s.sources) ? s.sources.map(clean) : [],
      links: (Array.isArray(s.links) ? s.links : []).filter(l => knownLinks.has(l)),
      significance: ['actively_exploited', 'poc_available', 'advisory', 'research'].includes(s.significance) ? s.significance : 'advisory',
      summary: clean(s.summary),
      soc_action: clean(s.soc_action),
    }))
  : data.items.map(i => ({ headline: i.title, sources: [i.source], links: [i.link], significance: 'advisory', summary: i.summary.slice(0, 300), soc_action: 'review' })));
out.top_story = clean(out.top_story);

const allIocs = { ips: new Set(), domains: new Set(), hashes: new Set(), cves: new Set() };
for (const i of data.items) {
  (i.extracted_iocs?.ips ?? []).forEach(v => allIocs.ips.add(v));
  (i.extracted_iocs?.domains ?? []).forEach(v => allIocs.domains.add(v));
  (i.extracted_iocs?.hashes ?? []).forEach(v => allIocs.hashes.add(v));
  (i.extracted_iocs?.cves ?? []).forEach(v => allIocs.cves.add(v));
  (i.feed_iocs ?? []).forEach(ind => {
    if (/ip/i.test(ind.type)) allIocs.ips.add(ind.value);
    else if (/domain|hostname/i.test(ind.type)) allIocs.domains.add(ind.value);
    else if (/hash|sha|md5/i.test(ind.type)) allIocs.hashes.add(ind.value);
  });
}
const defang = s => s.replace(/\./g, '[.]');
const sig = { actively_exploited: ':fire:', poc_available: ':warning:', advisory: ':memo:', research: ':microscope:' };

const slackText = `:newspaper: *Daily Threat Intel Bulletin* — ${new Date().toISOString().slice(0, 10)}\n` +
  `*Top story:* ${out.top_story ?? stories[0]?.headline ?? 'n/a'}\n\n` +
  stories.map(s => `${sig[s.significance] ?? ':memo:'} *${s.headline}* _(${(s.sources ?? []).join(', ')})_\n${s.summary}\n*SOC action:* ${s.soc_action ?? 'none'}`).join('\n\n') +
  `\n\n:pushpin: *IOC appendix (defanged)*\n` +
  `CVEs: ${[...allIocs.cves].join(', ') || 'none'}\n` +
  `IPs: ${[...allIocs.ips].map(defang).join(', ') || 'none'}\n` +
  `Domains: ${[...allIocs.domains].map(defang).join(', ') || 'none'}\n` +
  `Hashes: ${[...allIocs.hashes].map(h => h.slice(0, 16) + '…').join(', ') || 'none'}`;

const html = `<h2>Daily Threat Intel Bulletin — ${new Date().toISOString().slice(0, 10)}</h2>` +
  `<p><b>Top story:</b> ${out.top_story ?? ''}</p>` +
  stories.map(s => `<h3>${s.headline}</h3><p><i>${(s.sources ?? []).join(', ')} — ${s.significance}</i><br/>${s.summary}<br/><b>SOC action:</b> ${s.soc_action ?? 'none'}<br/>${(s.links ?? []).filter(Boolean).map(l => `<a href="${l}">${l}</a>`).join('<br/>')}</p>`).join('') +
  `<h3>IOC appendix (defanged)</h3><pre>CVEs: ${[...allIocs.cves].join(', ') || 'none'}\nIPs: ${[...allIocs.ips].map(defang).join(', ') || 'none'}\nDomains: ${[...allIocs.domains].map(defang).join(', ') || 'none'}\nSHA/MD5: ${[...allIocs.hashes].join(', ') || 'none'}</pre>`;

return { json: { slackText, html, subject: `[TI] Daily bulletin — ${stories.length} stories, ${allIocs.ips.size + allIocs.domains.size + allIocs.hashes.size} IOCs` } };
